    bool const reportError = ((*options) & TypeAnnotationParsingOptions::REPORT_ERROR) != 0;
    ArenaVector<ir::AnnotationUsage *> annotations {Allocator()->Adapter()};
    if (Lexer()->GetToken().Type() == lexer::TokenType::PUNCTUATOR_AT) {
