{
    if (Lexer()->GetToken().Type() == lexer::TokenType::PUNCTUATOR_LESS_THAN) {
        Lexer()->NextToken();  // eat '<'
        Lexer()->NextToken();  // eat 'identifier'
        if (Lexer()->GetToken().Type() == lexer::TokenType::PUNCTUATOR_GREATER_THAN) {
            Lexer()->NextToken();  // eat '>'
            return true;
        }
    }

    return false;
}

